mapper.sql:
/* OrderMapper.adminOrderStartDeliveryWhere: 관리자 배송 시작 관리 공통 조회 조건 */
WHERE 1=1
  AND OD.ORD_DTL_STAT_CD = #{ordDtlStatCd}
  AND COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) > 0

/* OrderMapper.adminOrderWhere: 관리자 주문 목록 공통 조회 조건 */
WHERE 1 = 1
  AND OD.ORD_DTL_STAT_CD != 'ORD_DTL_STAT_00'



   AND OD.ORD_NO = #{searchValue}


   AND OD.GOODS_ID LIKE CONCAT('%', #{searchValue}, '%')




   AND COALESCE(OB.ORDER_DT, OB.REG_DT) >= #{startDateTime}
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) < #{endExclusiveDateTime}


   AND OB.ORDER_CONFIRM_DT >= #{startDateTime}
   AND OB.ORDER_CONFIRM_DT < #{endExclusiveDateTime}


   AND OD.ORD_DTL_STAT_CD = #{ordDtlStatCd}


   AND EXISTS (
       SELECT 1
         FROM ORDER_CHANGE_DETAIL OCD
        WHERE OCD.ORD_NO = OD.ORD_NO
          AND OCD.ORD_DTL_NO = OD.ORD_DTL_NO
          AND OCD.CHG_DTL_STAT_CD = #{chgDtlStatCd}
   )

mapper.select:
/* OrderMapper.countShopMypageOrderGroup: 쇼핑몰 마이페이지 주문내역 주문번호 건수 조회 */
SELECT COUNT(*)
  FROM ORDER_BASE OB
 WHERE OB.CUST_NO = #{custNo}
   AND OB.ORD_STAT_CD != 'ORD_STAT_00'
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) >= #{startDateTime}
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) < #{endExclusiveDateTime}
   AND EXISTS (
       SELECT 1
         FROM ORDER_DETAIL OD
        WHERE OD.ORD_NO = OB.ORD_NO
          AND OD.ORD_DTL_STAT_CD NOT IN ('ORD_DTL_STAT_00', 'ORD_DTL_STAT_99')
   )

/* OrderMapper.getShopMypageOrderGroupList: 쇼핑몰 마이페이지 주문내역 주문번호 목록 페이징 조회 */
SELECT OB.ORD_NO
     , DATE_FORMAT(COALESCE(OB.ORDER_DT, OB.REG_DT), '%Y-%m-%d %H:%i:%s') AS ORDER_DT
  FROM ORDER_BASE OB
 WHERE OB.CUST_NO = #{custNo}
   AND OB.ORD_STAT_CD != 'ORD_STAT_00'
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) >= #{startDateTime}
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) < #{endExclusiveDateTime}
   AND EXISTS (
       SELECT 1
         FROM ORDER_DETAIL OD
        WHERE OD.ORD_NO = OB.ORD_NO
          AND OD.ORD_DTL_STAT_CD NOT IN ('ORD_DTL_STAT_00', 'ORD_DTL_STAT_99')
   )
 ORDER BY COALESCE(OB.ORDER_DT, OB.REG_DT) DESC, OB.ORD_NO DESC
 LIMIT #{pageSize} OFFSET #{offset}

/* OrderMapper.getShopMypageOrderDetailList: 쇼핑몰 마이페이지 주문내역 주문상세 목록 조회 */ SELECT OD.ORD_NO , OD.ORD_DTL_NO , OD.ORD_DTL_STAT_CD , FN_GET_CODE_NM('ORD_DTL_STAT', OD.ORD_DTL_STAT_CD) AS ORD_DTL_STAT_NM , CASE WHEN ACTIVE_CLAIM.CHG_DTL_STAT_CD IS NOT NULL THEN ACTIVE_CLAIM.CHG_DTL_STAT_CD ELSE OD.ORD_DTL_STAT_CD END AS DISPLAY_ORD_DTL_STAT_CD , CASE WHEN ACTIVE_CLAIM.CHG_DTL_STAT_NM IS NOT NULL THEN ACTIVE_CLAIM.CHG_DTL_STAT_NM ELSE FN_GET_CODE_NM('ORD_DTL_STAT', OD.ORD_DTL_STAT_CD) END AS DISPLAY_ORD_DTL_STAT_NM , CASE WHEN OD.ORD_DTL_STAT_CD = 'ORD_DTL_STAT_06' AND COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) > 0 AND ACTIVE_CLAIM.CHG_DTL_STAT_CD IS NULL THEN TRUE ELSE FALSE END AS RETURN_APPLYABLE_YN , CASE WHEN OD.ORD_DTL_STAT_CD = 'ORD_DTL_STAT_06' AND COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) > 0 AND ACTIVE_CLAIM.CHG_DTL_STAT_CD IS NULL THEN TRUE ELSE FALSE END AS EXCHANGE_APPLYABLE_YN , CASE WHEN ACTIVE_CLAIM.CHG_GB_CD = 'R' THEN TRUE ELSE FALSE END AS ACTIVE_RETURN_CLAIM_YN , CASE WHEN ACTIVE_CLAIM.CHG_GB_CD = 'E' THEN TRUE ELSE FALSE END AS ACTIVE_EXCHANGE_CLAIM_YN , OD.GOODS_ID , GB.GOODS_NM , OD.SIZE_ID , OD.ORD_QTY , COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) AS CANCELABLE_QTY , OD.SUPPLY_AMT , OD.SALE_AMT , OD.ADD_AMT , OD.GOODS_CPN_DC_AMT AS GOODS_COUPON_DISCOUNT_AMT , OD.CART_CPN_DC_AMT AS CART_COUPON_DISCOUNT_AMT , OD.POINT_USE_AMT AS POINT_USE_AMT , OD.GOODS_CPN_NO , OD.CART_CPN_NO , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = OD.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH FROM ORDER_DETAIL OD JOIN ORDER_BASE OB ON OB.ORD_NO = OD.ORD_NO LEFT JOIN ( SELECT OCD.ORD_NO , OCD.ORD_DTL_NO , OCB.CHG_GB_CD , OCD.CHG_DTL_STAT_CD , FN_GET_CODE_NM('CHG_DTL_STAT', OCD.CHG_DTL_STAT_CD) AS CHG_DTL_STAT_NM FROM ORDER_CHANGE_DETAIL OCD JOIN ORDER_CHANGE_BASE OCB ON OCB.CLM_NO = OCD.CLM_NO AND OCB.ORD_NO = OCD.ORD_NO WHERE OCB.CHG_GB_CD IN ('R', 'E') AND OCD.ORD_NO IN
#{ordNo}
AND COALESCE(OCB.CHG_STAT_CD, '') != 'CHG_STAT_02' AND ( (OCB.CHG_GB_CD = 'R' AND COALESCE(OCD.CHG_DTL_STAT_CD, '') NOT IN ('CHG_DTL_STAT_14', 'CHG_DTL_STAT_19')) OR (OCB.CHG_GB_CD = 'E' AND COALESCE(OCD.CHG_DTL_STAT_CD, '') NOT IN ('CHG_DTL_STAT_29', 'CHG_DTL_STAT_33', 'CHG_DTL_STAT_39')) ) AND NOT EXISTS ( SELECT 1 FROM ORDER_CHANGE_DETAIL NEXT_OCD JOIN ORDER_CHANGE_BASE NEXT_OCB ON NEXT_OCB.CLM_NO = NEXT_OCD.CLM_NO AND NEXT_OCB.ORD_NO = NEXT_OCD.ORD_NO WHERE NEXT_OCD.ORD_NO = OCD.ORD_NO AND NEXT_OCD.ORD_DTL_NO = OCD.ORD_DTL_NO AND NEXT_OCB.CHG_GB_CD IN ('R', 'E') AND COALESCE(NEXT_OCB.CHG_STAT_CD, '') != 'CHG_STAT_02' AND ( (NEXT_OCB.CHG_GB_CD = 'R' AND COALESCE(NEXT_OCD.CHG_DTL_STAT_CD, '') NOT IN ('CHG_DTL_STAT_14', 'CHG_DTL_STAT_19')) OR (NEXT_OCB.CHG_GB_CD = 'E' AND COALESCE(NEXT_OCD.CHG_DTL_STAT_CD, '') NOT IN ('CHG_DTL_STAT_29', 'CHG_DTL_STAT_33', 'CHG_DTL_STAT_39')) ) AND ( COALESCE(NEXT_OCB.CHG_DT, '') > COALESCE(OCB.CHG_DT, '') OR ( COALESCE(NEXT_OCB.CHG_DT, '') = COALESCE(OCB.CHG_DT, '') AND NEXT_OCD.CLM_NO > OCD.CLM_NO ) ) ) ) ACTIVE_CLAIM ON ACTIVE_CLAIM.ORD_NO = OD.ORD_NO AND ACTIVE_CLAIM.ORD_DTL_NO = OD.ORD_DTL_NO LEFT JOIN GOODS_BASE GB ON GB.GOODS_ID = OD.GOODS_ID WHERE OD.ORD_NO IN
#{ordNo}
AND OD.ORD_DTL_STAT_CD != 'ORD_DTL_STAT_00' ORDER BY COALESCE(OB.ORDER_DT, OB.REG_DT) DESC, OD.ORD_NO DESC, OD.ORD_DTL_NO ASC

/* OrderMapper.countShopOrderAddressName: 쇼핑몰 주문서 배송지 별칭 중복 건수 조회 */
SELECT COUNT(1)
  FROM CUSTOMER_ADDRESS
 WHERE CUST_NO = #{custNo}
   AND ADDRESS_NM = #{addressNm}

/* OrderMapper.countShopOrderAddress: 쇼핑몰 주문서 배송지 단건 존재 여부 조회 */
SELECT COUNT(1)
  FROM CUSTOMER_ADDRESS
 WHERE CUST_NO = #{custNo}
   AND ADDRESS_NM = #{addressNm}

mapper.insert:
/* OrderMapper.insertShopOrderBase: 쇼핑몰 주문 마스터 등록 */
INSERT INTO ORDER_BASE (
       ORD_NO
     , CUST_NO
     , ORD_STAT_CD
     , RCV_NM
     , RCV_POST_NO
     , RCV_ADDR_BASE
     , RCV_ADDR_DTL
     , DELV_CPN_NO
     , DELV_CPN_DC_AMT
     , ORD_DELV_AMT
     , REFUND_BANK_CD
     , REFUND_BANK_NO
     , REFUND_HOLDER_NM
     , CART_YN
     , DEVICE_GB_CD
     , REG_NO
     , UDT_NO
) VALUES (
       #{ordNo}
     , #{custNo}
     , #{ordStatCd}
     , #{rcvNm}
     , #{rcvPostNo}
     , #{rcvAddrBase}
     , #{rcvAddrDtl}
     , #{delvCpnNo}
     , #{delvCpnDcAmt}
     , #{ordDelvAmt}
     , #{refundBankCd}
     , #{refundBankNo}
     , #{refundHolderNm}
     , #{cartYn}
     , #{deviceGbCd}
     , #{regNo}
     , #{udtNo}
)

/* OrderMapper.insertShopOrderDetail: 쇼핑몰 주문 상세 등록 */
INSERT INTO ORDER_DETAIL (
       ORD_NO
     , ORD_DTL_NO
     , ORD_GB_CD
     , ORD_DTL_STAT_CD
     , CUST_NO
     , GOODS_ID
     , SIZE_ID
     , SUPPLY_AMT
     , SALE_AMT
     , ADD_AMT
     , ORD_QTY
     , CNC_QTY
     , RMN_QTY
     , GOODS_CPN_NO
     , GOODS_CPN_DC_AMT
     , CART_CPN_NO
     , CART_CPN_DC_AMT
     , POINT_USE_AMT
     , POINT_SAVE_AMT
     , EXHIBITION_NO
     , REG_NO
     , UDT_NO
) VALUES (
       #{ordNo}
     , #{ordDtlNo}
     , #{ordGbCd}
     , #{ordDtlStatCd}
     , #{custNo}
     , #{goodsId}
     , #{sizeId}
     , #{supplyAmt}
     , #{saleAmt}
     , #{addAmt}
     , #{ordQty}
     , #{cncQty}
     , #{rmnQty}
     , #{goodsCpnNo}
     , #{goodsCpnDcAmt}
     , #{cartCpnNo}
     , #{cartCpnDcAmt}
     , #{pointUseAmt}
     , #{pointSaveAmt}
     , #{exhibitionNo}
     , #{regNo}
     , #{udtNo}
)

/* OrderMapper.insertShopPayment: 쇼핑몰 결제 정보 등록 */
INSERT INTO PAYMENT (
       ORD_NO
     , CUST_NO
     , PAY_STAT_CD
     , PAY_GB_CD
     , PAY_METHOD_CD
     , ORD_GB_CD
     , PG_GB_CD
     , ORG_PAY_NO
     , CLM_NO
     , PAY_AMT
     , DEVICE_GB_CD
     , REQ_RAW_JSON
     , REG_NO
     , UDT_NO
) VALUES (
       #{ordNo}
     , #{custNo}
     , #{payStatCd}
     , #{payGbCd}
     , #{payMethodCd}
     , #{ordGbCd}
     , #{pgGbCd}
     , #{orgPayNo}
     , #{clmNo}
     , #{payAmt}
     , #{deviceGbCd}
     , #{reqRawJson}
     , #{regNo}
     , #{udtNo}
)

/* OrderMapper.insertShopOrderChangeBase: 주문변경 마스터 등록 */
INSERT INTO ORDER_CHANGE_BASE (
       CLM_NO
     , ORD_NO
     , CHG_GB_CD
     , CHG_DT
     , CHG_COMPLETE_DT
     , CHG_STAT_CD
     , PAY_DELV_AMT
     , REG_NO
     , UDT_NO
) VALUES (
