     , #{ordNo}
     , #{chgGbCd}
     , #{chgDt}
     , #{chgCompleteDt}
     , #{chgStatCd}
     , #{payDelvAmt}
     , #{regNo}
     , #{udtNo}
)

/* OrderMapper.insertShopOrderChangeDetail: 주문변경 상세 등록 */
INSERT INTO ORDER_CHANGE_DETAIL (
       CLM_NO
     , ORD_NO
     , ORD_DTL_NO
