/* OrderMapper.insertShopOrderChangeExchangeAddress: 주문변경 회수지/도착지 주소 등록 */
INSERT INTO ORDER_CHANGE_EXCHANGE_ADDRESS (
       CLM_NO
     , CLM_ADDR_GB_CD
     , ADDR_NAME
     , ADDR_POST_NO
     , ADDR_BASE
     , ADDR_DTL
     , REG_NO
     , UDT_NO
) VALUES (
       #{clmNo}
     , #{clmAddrGbCd}
     , #{addrName}
     , #{addrPostNo}
     , #{addrBase}
     , #{addrDtl}
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* OrderMapper.updateShopOrderBaseStatus: 쇼핑몰 주문 마스터 상태 변경 */
UPDATE ORDER_BASE
   SET ORD_STAT_CD = #{ordStatCd}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE ORD_NO = #{ordNo}

/* OrderMapper.updateShopOrderBaseFullCancel: 전체취소 주문 마스터 상태와 배송비쿠폰 적용 정보를 함께 갱신 */
UPDATE ORDER_BASE
   SET ORD_STAT_CD = #{ordStatCd}
     , DELV_CPN_NO = NULL
     , DELV_CPN_DC_AMT = 0
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE ORD_NO = #{ordNo}

/* OrderMapper.updateShopOrderBaseStatusAndDates: 쇼핑몰 주문 마스터 상태와 결제 시각 변경 */
UPDATE ORDER_BASE
   SET ORD_STAT_CD = #{ordStatCd}

     , ORDER_DT = #{orderDt}


     , ORDER_CONFIRM_DT = #{orderConfirmDt}

     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE ORD_NO = #{ordNo}

/* OrderMapper.updateShopOrderDetailStatus: 쇼핑몰 주문 상세 상태 일괄 변경 */
UPDATE ORDER_DETAIL
   SET ORD_DTL_STAT_CD = #{ordDtlStatCd}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE ORD_NO = #{ordNo}

/* OrderMapper.updateAdminOrderDetailStatusByOrdDtlNoList: 관리자 주문 상세 상태 일괄 변경 */
UPDATE ORDER_DETAIL
   SET ORD_DTL_STAT_CD = #{toOrdDtlStatCd}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE ORD_NO = #{ordNo}
   AND ORD_DTL_STAT_CD = #{fromOrdDtlStatCd}
   AND COALESCE(RMN_QTY, ORD_QTY, 0) > 0
   AND ORD_DTL_NO IN

	#{ordDtlNo}

/* OrderMapper.updateAdminOrderStartDeliveryPrepareList: 관리자 배송 준비중 일괄 처리 */ UPDATE ORDER_DETAIL OD JOIN (
SELECT #{item.ordNo} AS ORD_NO , #{item.ordDtlNo} AS ORD_DTL_NO , #{item.delvCompCd} AS DELV_COMP_CD , #{item.invoiceNo} AS INVOICE_NO
) REQ ON REQ.ORD_NO = OD.ORD_NO AND REQ.ORD_DTL_NO = OD.ORD_DTL_NO SET OD.ORD_DTL_STAT_CD = #{toOrdDtlStatCd} , OD.DELV_COMP_CD = REQ.DELV_COMP_CD , OD.INVOICE_NO = REQ.INVOICE_NO , OD.DELV_START_DT = NOW() , OD.UDT_NO = #{udtNo} , OD.UDT_DT = NOW() WHERE OD.ORD_DTL_STAT_CD = #{fromOrdDtlStatCd} AND COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) > 0

/* OrderMapper.updateAdminOrderStartDeliveryStatusList: 관리자 배송 상태 일괄 변경 */
UPDATE ORDER_DETAIL OD
  JOIN (

		SELECT #{item.ordNo} AS ORD_NO
		     , #{item.ordDtlNo} AS ORD_DTL_NO

  ) REQ
    ON REQ.ORD_NO = OD.ORD_NO
   AND REQ.ORD_DTL_NO = OD.ORD_DTL_NO
   SET OD.ORD_DTL_STAT_CD = #{toOrdDtlStatCd}

     , OD.DELV_COMPLETE_DT = NOW()

     , OD.UDT_NO = #{udtNo}
     , OD.UDT_DT = NOW()
 WHERE OD.ORD_DTL_STAT_CD = #{fromOrdDtlStatCd}
   AND COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) > 0

/* OrderMapper.updateShopOrderDetailCancelQuantity: 주문상세 취소 수량/상태와 쿠폰/포인트 할인금액 차감 반영 */
UPDATE ORDER_DETAIL
   SET CNC_QTY = COALESCE(CNC_QTY, 0) + #{cancelQty}
     , RMN_QTY = COALESCE(RMN_QTY, ORD_QTY, 0) - #{cancelQty}
     , ORD_DTL_STAT_CD = #{nextOrdDtlStatCd}
     , GOODS_CPN_DC_AMT = GREATEST(COALESCE(GOODS_CPN_DC_AMT, 0) - #{goodsCpnDcAmt}, 0)
     , CART_CPN_DC_AMT = GREATEST(COALESCE(CART_CPN_DC_AMT, 0) - #{cartCpnDcAmt}, 0)
     , POINT_USE_AMT = GREATEST(COALESCE(POINT_USE_AMT, 0) - #{pointUseAmt}, 0)
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE ORD_NO = #{ordNo}
   AND ORD_DTL_NO = #{ordDtlNo}
   AND COALESCE(RMN_QTY, ORD_QTY, 0) >= #{cancelQty}

/* OrderMapper.updateShopPaymentSuccess: 카드/계좌이체 승인 성공 결제 정보 갱신 */
UPDATE PAYMENT
   SET PAY_STAT_CD = #{payStatCd}
     , APRV_AMT = #{aprvAmt}
     , TOSS_PAYMENT_KEY = #{tossPaymentKey}
     , TOSS_PAYMENT_KEY_HASH = #{tossPaymentKeyHash}
     , TRADE_NO = #{tradeNo}
     , APPR_NO = #{apprNo}
     , RSP_CODE = #{rspCode}
     , RSP_MSG = #{rspMsg}
     , CARD_CD = #{cardCd}
     , CARD_NO = #{cardNo}
     , RSP_RAW_JSON = #{rspRawJson}
     , APPR_DT = #{apprDt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PAY_NO = #{payNo}

/* OrderMapper.updateShopPaymentWaitingDeposit: 무통장입금 발급 성공 결제 정보 갱신 */
UPDATE PAYMENT
   SET PAY_STAT_CD = #{payStatCd}
     , APRV_AMT = #{aprvAmt}
     , TOSS_PAYMENT_KEY = #{tossPaymentKey}
     , TOSS_PAYMENT_KEY_HASH = #{tossPaymentKeyHash}
     , TRADE_NO = #{tradeNo}
     , RSP_CODE = #{rspCode}
     , RSP_MSG = #{rspMsg}
     , BANK_CD = #{bankCd}
     , BANK_NO = #{bankNo}
     , VACT_HOLDER_NM = #{vactHolderNm}
     , VACT_DUE_DT = #{vactDueDt}
     , RSP_RAW_JSON = #{rspRawJson}
     , APPR_DT = #{apprDt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PAY_NO = #{payNo}

/* OrderMapper.updateShopPaymentFailure: 결제 실패/취소 정보 갱신 */
UPDATE PAYMENT
   SET PAY_STAT_CD = #{payStatCd}
     , RSP_CODE = #{rspCode}
     , RSP_MSG = #{rspMsg}
     , RSP_RAW_JSON = #{rspRawJson}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PAY_NO = #{payNo}

/* OrderMapper.updateShopPaymentCancelSuccess: 환불 결제 성공 결과 갱신 */
UPDATE PAYMENT
   SET PAY_STAT_CD = #{payStatCd}
     , CNL_AMT = #{cnlAmt}
     , TRADE_NO = #{tradeNo}
     , RSP_CODE = #{rspCode}
     , RSP_MSG = #{rspMsg}
     , RSP_RAW_JSON = #{rspRawJson}

     , APPR_DT = #{apprDt}

     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PAY_NO = #{payNo}

/* OrderMapper.updateShopPaymentCancelFailure: 환불 결제 실패 결과 갱신 */
UPDATE PAYMENT
   SET PAY_STAT_CD = #{payStatCd}
     , RSP_CODE = #{rspCode}
     , RSP_MSG = #{rspMsg}
     , RSP_RAW_JSON = #{rspRawJson}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PAY_NO = #{payNo}

/* OrderMapper.updateShopPaymentWebhook: 웹훅 반영 결제 정보 갱신 */
UPDATE PAYMENT
   SET PAY_STAT_CD = #{payStatCd}
     , RSP_CODE = #{rspCode}
     , RSP_MSG = #{rspMsg}
     , WEBHOOK_RAW_JSON = #{webhookRawJson}
     , WEBHOOK_DT = #{webhookDt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PAY_NO = #{payNo}

/* OrderMapper.updateShopCustomerCouponUse: 선택 고객쿠폰 사용 처리 */
UPDATE CUSTOMER_COUPON
   SET CPN_USE_YN = #{cpnUseYn}
     , ORD_NO = #{ordNo}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND CUST_CPN_NO IN

	#{custCpnNo}

/* OrderMapper.restoreShopCustomerCouponUse: 주문번호 기준 고객쿠폰 사용 처리 원복
   - ORDER_DETAIL의 GOODS_CPN_NO, CART_CPN_NO와 ORDER_BASE의 DELV_CPN_NO를 읽어 해당 CUST_CPN_NO만 원복
   - CUSTOMER_COUPON.ORD_NO = #{ordNo} 조건으로 재사용된 쿠폰(다른 주문에 이미 사용된 경우)은 원복 제외 */
UPDATE CUSTOMER_COUPON
   SET CPN_USE_YN = 'N'
     , ORD_NO = NULL
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND ORD_NO = #{ordNo}
   AND CUST_CPN_NO IN (
       SELECT cpn_no
         FROM (
              SELECT GOODS_CPN_NO AS cpn_no
                FROM ORDER_DETAIL
               WHERE ORD_NO = #{ordNo}
                 AND GOODS_CPN_NO IS NOT NULL
               UNION
              SELECT CART_CPN_NO AS cpn_no
                FROM ORDER_DETAIL
               WHERE ORD_NO = #{ordNo}
                 AND CART_CPN_NO IS NOT NULL
               UNION
              SELECT DELV_CPN_NO AS cpn_no
                FROM ORDER_BASE
               WHERE ORD_NO = #{ordNo}
                 AND DELV_CPN_NO IS NOT NULL
         ) AS cpn_list
   )

/* OrderMapper.restoreShopCustomerCouponUseByCustCpnNoList: 고객쿠폰번호 목록 기준 고객쿠폰 사용 처리 원복 */
UPDATE CUSTOMER_COUPON
   SET CPN_USE_YN = 'N'
     , ORD_NO = NULL
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND CUST_CPN_NO IN

	#{custCpnNo}


   AND ORD_NO = #{ordNo}

/* OrderMapper.updateShopCustomerPointUseAmt: 포인트 마스터 사용 금액 차감 */
UPDATE CUSTOMER_POINT_BASE
   SET USE_AMT = USE_AMT + #{useAmt}
     , RMN_AMT = RMN_AMT - #{useAmt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PNT_NO = #{pntNo}

/* OrderMapper.restoreShopCustomerPointUseAmt: 포인트 마스터 사용 금액 복구 */
UPDATE CUSTOMER_POINT_BASE
   SET USE_AMT = USE_AMT - #{restoreAmt}
     , RMN_AMT = RMN_AMT + #{restoreAmt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PNT_NO = #{pntNo}

mapper.insert:
/* OrderMapper.insertShopOrderPointDetail: 주문 결제 포인트 상세 이력 등록 */
INSERT INTO CUSTOMER_POINT_DETAIL (
       PNT_NO
     , PNT_AMT
     , ORD_NO
     , BIGO
     , REG_NO
) VALUES (
       #{pntNo}
     , #{pntAmt}
     , #{ordNo}
     , #{bigo}
     , #{regNo}
)

