/* OrderMapper.updateShopOrderAddress: 쇼핑몰 주문서 배송지 수정 */
UPDATE CUSTOMER_ADDRESS
   SET ADDRESS_NM = #{addressNm}
     , POST_NO = #{postNo}
     , BASE_ADDRESS = #{baseAddress}
     , DETAIL_ADDRESS = #{detailAddress}
     , PHONE_NUMBER = #{phoneNumber}
     , RSV_NM = #{rsvNm}
